+    /// Generate URL bar RGBA for compositing
+    fn generateUrlBarRgba(self: *ToolbarRenderer, width: u32) ![]u8 {
+        const display_text = if (self.url_focused)
+            self.url_buffer[0..self.url_len]
+        else
+            self.current_url;
+        return self.generateUrlBarWithText(
+            width,
